bool test_observer_reset(const std::string& observerName, const std::string& targetName) {
    // 1. Create observer and target nodes using TestObserverReset class
    auto observer = std::make_shared<TestObserverReset>(observerName);
    auto target = std::make_shared<TestObserverReset>(targetName);

    // 2. Get the observer graph instance using ObserverGraph::getInstance()
    auto graph = reaction::ObserverGraph::getInstance();

    // 3. Add observer relationship using addObserver()
    graph.addObserver(target, observer);

    // 4. Trigger notification on target using valueChanged()
    target->valueChanged();

    // 5. Verify observer was notified by checking call count
    if (observer->getCallCount() == 0) {
        return false; // Observer wasn't notified initially
    }

    // 6. Record call count before reset
    int callCountBeforeReset = observer->getCallCount();

    // 7. Reset observer node using resetObserver()
    graph.resetNode(observer);

    // 8. Trigger notification again on target
    target->valueChanged();

    // 9. Verify observer was not notified by comparing call count with previous
    int callCountAfterReset = observer->getCallCount();
    bool result = (callCountAfterReset == callCountBeforeReset);

    // 10. Return true if verification passes, false otherwise
    return result;
}

