 * Function: Test node closure functionality
 *
 * @param nodeName Name for the observer node
 * @return bool Whether node closure worked correctly (relationships cleaned up)
 */
bool test_node_closure(const std::string& nodeName) {
    // 1. Create two observer nodes (source and target)
    auto sourceNode = std::make_shared<TestObserverClosure>("source");
    auto targetNode = std::make_shared<TestObserverClosure>("target");

    // 2. Get the observer graph instance
    auto graphInstance = reaction::ObserverGraph::getInstance();

    // 3. Add an observer relationship from source to target
    graphInstance.addObserver(sourceNode, targetNode);

    // 4. Notify the source node
    sourceNode->notify(true);

    // 5. Verify the target node was notified
    if (!targetNode->wasChanged() || targetNode->getCallCount() != 1) {
        return false; // Notification failed
    }

    // 6. Reset the target node's state
    // Since TestObserverClosure doesn't have a reset method, we'll create a new one
    targetNode = std::make_shared<TestObserverClosure>("target");

    // 7. Close the source node
    sourceNode->close();

    // 8. Notify the source node again (should not propagate)
    sourceNode->notify(true);

    // 9. Verify the target node was not notified
    if (targetNode->wasChanged() || targetNode->getCallCount() != 0) {
        return false; // Closure failed - notification still propagated
    }

    // 10. Return success status
    return true;
