    auto sourceNode = std::make_shared<TestObserverClosure>("source");
    auto targetNode = std::make_shared<TestObserverClosure>("target");

    // 2. Get the observer graph instance
    auto graphInstance = reaction::ObserverGraph::getInstance();

    // 3. Add an observer relationship from source to target
    graphInstance.addObserver(sourceNode, targetNode);

    // 4. Notify the source node
    sourceNode->notify(true);

    // 5. Verify the target node was notified
    if (!targetNode->wasChanged() || targetNode->getCallCount() != 1) {
        return false; // Notification failed
    }

    // 6. Reset the target node's state
