```cpp
#pragma once

#include <reaction/memory/memory_config.h>
#include <cstddef>

namespace test_reaction {

struct TinyPod {
    int a;
    int b;
};

struct MediumPod {
    double values[3];
};

struct LargePod {
    std::byte payload[128];
};

struct SboTraitSummary {
    bool tinyAlwaysSbo;
    bool tinyForceHeap;
    bool mediumConditionalSbo;
    bool mediumForceHeap;
    bool largeForceHeap;
    std::size_t alwaysThreshold;
    std::size_t conditionalThreshold;
    std::size_t maxStackUsage;
};

SboTraitSummary analyze_sbo_traits() {
    using namespace reaction::memory;

    // Get SBO traits for each type
    auto tinyTraits = SBOTraits<TinyPod>();
    auto mediumTraits = SBOTraits<MediumPod>();
    auto largeTraits = SBOTraits<LargePod>();

    // Get configuration thresholds
    std::size_t alwaysThreshold = SBOTraits<void>::ALWAYS_SBO_SIZE;
    std::size_t conditionalThreshold = SBOTraits<void>::CONDITIONAL_SBO_SIZE;
    std::size_t maxStackUsage = SBOTraits<void>::MAX_SBO_STACK_USAGE;

    // Populate summary
    SboTraitSummary summary{
        .tinyAlwaysSbo = tinyTraits.always_sbo,
        .tinyForceHeap = tinyTraits.force_heap,
        .mediumConditionalSbo = !mediumTraits.always_sbo && !mediumTraits.force_heap,
